/**
 * Tests for plugin entry point orchestration (index.ts).
 *
 * Validates the glue logic that coordinates RecallEngine + EngramSearchSource:
 * - Query extraction happens before engram search (not raw prompt)
 * - Engram results are capped at maxResults after multi-query merge
 * - Engram and recall produce separate sections
 * - Deduplication works across queries
 *
 * These tests simulate what index.ts does without needing a running
 * OpenClaw gateway — they test the orchestration patterns directly.
 *
 * Run: npx tsx test/plugin-entry.test.ts
 */
import { extractQueries } from "../src/query-extractor.js";
import { EngramSearchSource, type EngramApi, type EngramSearchResult } from "../src/sources/engram-search.js";

let passed = 0;
let failed = 0;

function assert(condition: boolean, name: string) {
  if (condition) {
    passed++;
    console.log(`  ✅ ${name}`);
  } else {
    failed++;
    console.log(`  ❌ ${name}`);
  }
}

// === Helpers ===

/**
 * Simulate the index.ts engram orchestration pattern:
 * 1. Extract queries from raw prompt
 * 2. Search engram with each extracted query (up to 3)
 * 3. Deduplicate by reference
 * 4. Cap at maxResults
 */
async function simulateEngramOrchestration(
  prompt: string,
  engramSource: EngramSearchSource,
  maxResults: number,
): Promise<{ reference: string; text: string; score: number }[]> {
  const { queries } = extractQueries(prompt);
  if (queries.length === 0) return [];

  const jobs = queries.slice(0, 3).map(q =>
    engramSource.search(q, 0.3).catch(() => [])
  );
  const allResults = (await Promise.all(jobs)).flat();

  // Deduplicate, sort by score, take top N (mirrors index.ts logic)
  const seen = new Set<string>();
  const deduped = allResults.filter(s => {
    if (seen.has(s.reference)) return false;
    seen.add(s.reference);
    return true;
  });

  return deduped
    .sort((a, b) => b.score - a.score)
    .slice(0, maxResults)
    .map(s => ({ reference: s.reference, text: s.text, score: s.score }));
}

function createMockEngramApi(resultsByQuery: Map<string, EngramSearchResult[]>): EngramApi {
  return {
    search: async (query: string, _excludeModels?: string[]) => {
      // Match on substring — real engram does fuzzy matching
      for (const [key, results] of resultsByQuery) {
        if (query.toLowerCase().includes(key.toLowerCase()) ||
            key.toLowerCase().includes(query.toLowerCase())) {
          return results;
        }
      }
      return [];
    },
  };
}

function makeEngramResult(model: string, label: string, type: string = "module"): EngramSearchResult {
  return {
    model,
    modelType: "code",
    node: { label, type, metadata: {} },
    edges: [],
  };
}

async function runTests() {
  // === Query extraction before engram search ===
  console.log("\n🔍 Query extraction strips metadata envelope");

  // Simulate a raw prompt with OpenClaw metadata
  const rawPrompt = `## 🧠 Recalled Context
Automatically retrieved based on the user's message.

Conversation info (untrusted metadata):
\`\`\`json
{
  "message_id": "6338",
  "sender_id": "2028789956",
  "sender": "Morpheis"
}
\`\`\`

Tell me about Tom Merkle and the Hashbranch org structure`;

  const { queries } = extractQueries(rawPrompt);
  // Should extract "Tom Merkle" and "Hashbranch", not search with JSON metadata
  const allQueriesJoined = queries.join(" ");
  assert(
    allQueriesJoined.includes("Tom Merkle") || allQueriesJoined.includes("Tom") && allQueriesJoined.includes("Merkle"),
    "extracted queries contain Tom Merkle (not raw JSON)",
  );
  assert(
    !allQueriesJoined.includes("message_id"),
    "extracted queries do NOT contain JSON metadata fields",
  );
  assert(
    !allQueriesJoined.includes("sender_id"),
    "extracted queries do NOT contain sender_id metadata",
  );

  // === Engram results capped at maxResults ===
  console.log("\n📏 Engram results capped at maxResults");

  // Create mock API that returns different results for different queries
  const resultMap = new Map<string, EngramSearchResult[]>();
  resultMap.set("Tom", [
    makeEngramResult("org", "Tom-Merkle", "person"),
    makeEngramResult("org", "Hashbranch", "org"),
    makeEngramResult("org", "Engineering", "team"),
  ]);
  resultMap.set("Hashbranch", [
    makeEngramResult("org", "Hashbranch", "org"),  // duplicate with Tom query
    makeEngramResult("org", "hb-fleet-rest", "service"),
    makeEngramResult("org", "hb-payment-rest", "service"),
    makeEngramResult("org", "hb-admin-portal", "service"),
  ]);

  const mockApi = createMockEngramApi(resultMap);
  const source = new EngramSearchSource(mockApi, 10); // high limit so source doesn't cap

  // With maxResults=5, should get at most 5 after dedup
  const results5 = await simulateEngramOrchestration(
    "Tell me about Tom Merkle and Hashbranch",
    source,
    5,
  );
  assert(results5.length <= 5, `maxResults=5 caps output (got ${results5.length})`);

  // With maxResults=3, should get at most 3
  const results3 = await simulateEngramOrchestration(
    "Tell me about Tom Merkle and Hashbranch",
    source,
    3,
  );
  assert(results3.length <= 3, `maxResults=3 caps output (got ${results3.length})`);

  // With maxResults=1, should get exactly 1
  const results1 = await simulateEngramOrchestration(
    "Tell me about Tom Merkle and Hashbranch",
    source,
    1,
  );
  assert(results1.length === 1, `maxResults=1 caps output (got ${results1.length})`);

  // === Deduplication across queries ===
  console.log("\n🔀 Deduplication across multi-query results");

  // "Hashbranch" appears in results for both "Tom" and "Hashbranch" queries
  const results = await simulateEngramOrchestration(
    "Tell me about Tom Merkle and Hashbranch",
    source,
    10, // high cap to not interfere
  );
  const hashbranchCount = results.filter(r => r.reference.includes("Hashbranch")).length;
  assert(hashbranchCount === 1, `Hashbranch appears only once after dedup (got ${hashbranchCount})`);

  // === Score-based ranking across queries ===
  console.log("\n📊 Score-based ranking across queries");

  // Create mock where different queries return results with different relevance.
  // "Tom Merkle" query should return Tom-Merkle (high score label match).
  // Verbatim query returns chitin results (low score, no query term overlap).
  const rankingResults: EngramSearchResult[] = [
    {
      model: "hashbranch",
      modelType: "org",
      node: { label: "Tom-Merkle", type: "person", metadata: { role: "CEO" } },
      edges: [{ direction: "out", relationship: "leads", target: "Hashbranch" }],
    },
    {
      model: "hashbranch",
      modelType: "org",
      node: { label: "Hashbranch", type: "org", metadata: {} },
      edges: [{ direction: "in", relationship: "leads", source: "Tom-Merkle" }],
    },
    {
      model: "chitin",
      modelType: "code",
      node: { label: "EmbeddingFactory", type: "function", metadata: {} },
      edges: [],
    },
  ];

  const rankingApi: EngramApi = {
    search: async () => rankingResults,
  };

  const rankingSource = new EngramSearchSource(rankingApi, 10);
  const rankedResults = await simulateEngramOrchestration(
    "Tell me about Tom Merkle at Hashbranch",
    rankingSource,
    5,
  );

  // Results should be sorted by score — Tom-Merkle and Hashbranch before EmbeddingFactory
  assert(rankedResults.length >= 2, "got results from score-based ranking");
  const scores = rankedResults.map(r => r.score);
  for (let i = 1; i < scores.length; i++) {
    assert(scores[i - 1] >= scores[i], `results sorted by score: [${i-1}]=${scores[i-1].toFixed(2)} >= [${i}]=${scores[i].toFixed(2)}`);
  }

  // Tom-Merkle should rank above EmbeddingFactory
  const tomIdx = rankedResults.findIndex(r => r.reference.includes("Tom-Merkle"));
  const embIdx = rankedResults.findIndex(r => r.reference.includes("EmbeddingFactory"));
  assert(
    embIdx === -1 || tomIdx < embIdx,
    "Tom-Merkle ranks above EmbeddingFactory (or EmbeddingFactory filtered out)",
  );

  // === Empty queries produce no engram results ===
  console.log("\n🚫 Edge cases");

  const emptyResults = await simulateEngramOrchestration("", source, 5);
  assert(emptyResults.length === 0, "empty prompt → no engram results");

  const casualResults = await simulateEngramOrchestration("hey", source, 5);
  // "hey" has no entities — extractQueries still returns verbatim,
  // but engram probably returns nothing for "hey"
  assert(casualResults.length === 0, "casual message with no entity matches → no engram results");

  // === Proper noun extraction from conversational messages ===
  console.log("\n💬 Conversational messages extract entities for engram");

  const conversational = extractQueries("How's the Hashbranch fleet system doing?");
  const hasHashbranch = conversational.queries.some(q => q.includes("Hashbranch"));
  assert(hasHashbranch, "conversational message extracts Hashbranch as entity");

  const casualEntity = extractQueries("How's OathKeeper going?");
  const hasOathKeeper = casualEntity.queries.some(q => q.includes("OathKeeper"));
  assert(hasOathKeeper, "casual-prefix message still extracts OathKeeper");

  // === Summary ===
  console.log(`\n${"=".repeat(40)}`);
  console.log(`Results: ${passed} passed, ${failed} failed`);
  if (failed > 0) process.exit(1);
}

runTests().catch((err) => {
  console.error("Test error:", err);
  process.exit(1);
});
